import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import com.google.gson.GsonBuilder;
import java.lang.reflect.Field;

class GsonBuilderTest {

  @Test
  void testDisableHtmlEscaping() throws Exception {
    GsonBuilder builder = new GsonBuilder();
    // Initially, escapeHtmlChars should be true (DEFAULT_ESCAPE_HTML)
    Field escapeHtmlCharsField = GsonBuilder.class.getDeclaredField("escapeHtmlChars");
    escapeHtmlCharsField.setAccessible(true);
    boolean initialValue = escapeHtmlCharsField.getBoolean(builder);
    assertTrue(initialValue, "escapeHtmlChars should be true by default");

    // Call disableHtmlEscaping and verify it returns the same builder instance
    GsonBuilder returnedBuilder = builder.disableHtmlEscaping();
    assertSame(builder, returnedBuilder, "disableHtmlEscaping should return the same GsonBuilder instance");

    // Verify escapeHtmlChars is now false
    boolean updatedValue = escapeHtmlCharsField.getBoolean(builder);
    assertFalse(updatedValue, "escapeHtmlChars should be false after disableHtmlEscaping");
  }
}
